                    </g>
                    <g id="regionNames">
                        <text v-for="rn in regionNames" :key="rn.key" text-anchor="middle" :x="rn.x" :y="rn.y" :id="`t_${rn.id}`" vector-effect="non-scaling-stroke">
                            <tspan :x="rn.x" dy="1em" class="region-name" >{{ rn.name }}</tspan>
                            <tspan v-if="statistic[rn.id]" :x="rn.x" dy="1.3em" class="statistic-value">{{ statistic[rn.id] }}</tspan>
                            <tspan v-else :x="rn.x" dy="1.3em" class="statistic-value">{{ zeroValue }}</tspan>
                        </text>
                    </g>
                    <g id="legend">
                        <text v-if="legend" class="legend" x="0" y="20">{{ legend }}</text>
                    </g>
                </svg>
            </div>
            <div class="control-panel">
                <div class="statistic-types">
                    <a-button
                        :type="isProjects ? 'primary': 'default'"
                        class="custom-button"
                        @click="changeStatisticType('projects')">
                        {{ $t('dashboard.projectButton') }}
                    </a-button>
                    <a-button
                        :type="isFunds ? 'primary': 'default'"
                        class="custom-button"
                        @click="changeStatisticType('funds')">
                        {{ $t('dashboard.fundingButton') }}
                    </a-button>
                </div>
                <div class="date-start">
                    <div class="label">{{ $t('dashboard.startDateLabel') }}</div>
                    <a-range-picker
                        class="custom-range-picker"
                        :disabled="isLoading"
                        :placeholder="[$t('dashboard.start'), $t('dashboard.end')]"
                        @change="onDateStartChange" />
                </div>
                <div class="dead-line">
                    <div class="label">{{ $t('dashboard.endDateLabel') }}</div>
                    <a-range-picker
                        class="custom-range-picker"
                        :disabled="isLoading"
                        :placeholder="[$t('dashboard.start'), $t('dashboard.end')]"
                        @change="onDeadLineChange" />
                </div>
                <div class="kz_detail">
                    <div class="title">
                        <div class="label">{{ $t('dashboard.totalKZ') }}</div>
                        <span class="value">{{ KZStat?.grand_total?.value }}</span>
                        <span class="measure-unit">{{ KZStat?.grand_total?.measure_unit }}</span>
                    </div>
                    <div class="st-grid">
                        <div v-for="(item, index) in KZStat?.statistic" :key="index" class="item">
                            <div class="progress">
                                <div class="label">
                                    <span>{{ $t('dashboard.progressText', { name: item.name, value: item.value, measure_unit: item.measure_unit }) }}</span>
                                </div>
                                <div class="pb-wrap">
                                    <a-progress
                                        class="custom-progress"
                                        :class="`trail-color-${index}`"
                                        :percent="Number(item.percent)"
                                        :show-info="false"
                                        :strokeWidth="21.45"
                                        :strokeColor="strokeColor(index)" />
                                    <div class="progress-text" :class="[
                                        {white: index === 0 || index === 3},
                                        {black: index === 1 || index === 2}
                                    ]">
                                        {{ $t('dashboard.percent', { percent: item.percent }) }}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </a-spin>
</template>

<script>
import {regionNames, regionIDs} from './regionNames.js'

export default {
    name: 'InvestProjectsWidget',
    data() {
        return {
            regionNames,
            regionIDs,
            statisticType: 'funds',
            zeroValue: '0.00',
            dateStart_start: null,
            dateStart_end: null,
            deadLine_start: null,
            deadLine_end: null,
            map_loading: false,
            legend: '',
            legendTypes: {
                funds: this.$t('dashboard.ob_tg'),
                projects: ''
            },
            rs_loading: false,
            kz_loading: false,
            selectedRegion: {
                name: '',
                id: ''
            },
            regionDetails: null,
            KZStat: null,
            statistic: {},
            strokeColors: [
                '#F94A1D',
                '#80CC33',
                '#33CCCC',
                '#8941D0'
            ],
            regionDetailsStyle: {
                top: '0px',
                left: '0px',
            },
            left: 0,
            top: 0
        }
    },
    created() {
        this.getStat()
    },
    mounted() {
        this.addListeners()
    },
    beforeDestroy() {
        this.removeListeners()
    },
    computed: {
        isFunds() {
            return this.statisticType === 'funds'
        },
        isProjects() {
            return this.statisticType === 'projects'
        },
        isLoading() {
            return this.map_loading || this.rs_loading || this.kz_loading
        },
        showRegionDetails() {
            return this.regionDetails?.statistic ? this.regionDetails.statistic.length > 0 : false
        }
    },
    methods: {
        projectWord(count) {
            const lastDigit = count % 10;
            const lastTwoDigits = count % 100;

            if (lastTwoDigits >= 11 && lastTwoDigits <= 19) {
                return this.$t('dashboard.projects');
            }
            if (lastDigit === 1) {
                return this.$t('dashboard.project');
            }
            if (lastDigit >= 2 && lastDigit <= 4) {
                return this.$t('dashboard.projectGenitive');
            }
            return this.$t('dashboard.projects');
        },
        strokeColor(index) {
            return this.strokeColors[index]
        },
        clearSelectedRegion() {
            if(this.selectedRegion.id) {
                const region = document.getElementById(this.selectedRegion.id)
                const text = document.getElementById(`t_${this.selectedRegion.id}`)
                if(region) region.classList.remove('selected')
                if(text) text.classList.remove('t_selected')
            }
            this.regionDetails = null
            this.selectedRegion ={
                name: '',
                id: ''
            }
            this.regionDetailsStyle = {
                top: '0px',
                left: '0px',
            }
            this.top = 0
            this.left = 0
        },
        getStat(forKZ=true) {
            this.getMapStat()
            if(this.selectedRegion.id) {
                this.getRegionStat(this.selectedRegion.id)
            }
            if(forKZ) {
                this.getKZStat()
            }
        },
        onDateStartChange(date, dateString) {
            [this.dateStart_start, this.dateStart_end] = dateString
            this.getStat()
        },
        onDeadLineChange(date, dateString) {
            [this.deadLine_start, this.deadLine_end] = dateString
            this.getStat()
        },
        changeStatisticType(type) {
            if(this.isLoading) return
            if(this.statisticType !== type) {
                this.statisticType = type
                this.getStat()
            }
        },
        getParams() {
            const params = {
                type: this.statisticType
            }
            if(this.dateStart_start)
                params.dateStart_start = this.dateStart_start
            if(this.dateStart_end)
                params.dateStart_end = this.dateStart_end
            if(this.deadLine_start)
                params.deadLine_start = this.deadLine_start
            if(this.deadLine_end)
                params.deadLine_end = this.deadLine_end
            return params
        },
        addMeasureUnits(data) {
            this.zeroValue = this.isFunds ? '0.00' : '0';
            return {
                grand_total: {
                    value: data.grand_total ? data.grand_total : this.$t('dashboard.noData'),
                    measure_unit: data.grand_total ? this.isFunds ? this.$t('dashboard.millionTenge') : this.projectWord(Number(data.grand_total)) : ''
                },
                statistic: data.statistic.map(each => {
                    each.measure_unit = this.isFunds ? this.$t('dashboard.millionTenge') : '';
                    return each;
                })
            };
        },
        async getKZStat() {
            this.kz_loading = true
            try {
                const { data } = await this.$http.get('/invest_projects_info/KZ00/region_statistics', {
                    params: this.getParams()
                })
                if(data) {
                    this.KZStat = this.addMeasureUnits(data)
                }
            } catch(e) {
                console.log(e)
            } finally {
                this.kz_loading = false
            }
        },
        async getRegionStat(regionID) {
            this.rs_loading = true
            try {
                const { data } = await this.$http.get(`/invest_projects_info/${regionID}/region_statistics`, {
                    params: this.getParams()
                })
                if(data) {
                    if(data.statistic.length) this.correctRegionDetailsStyle(data.statistic.length)
                    this.regionDetails = this.addMeasureUnits(data)
                }
            } catch(e) {
                console.log(e)
            } finally {
                this.rs_loading = false
            }
        },
        async getMapStat() {
            this.map_loading = true
            try {
                const { data } = await this.$http.get('/invest_projects_info/statistics', {
                    params: this.getParams()
                })
                if(data) {
                    this.statistic = data
                    this.legend = this.legendTypes[this.statisticType]
                }
            } catch(e) {
                console.log(e)
            } finally {
                this.map_loading = false
            }
        },
        addListeners() {
            this.regionIDs.forEach(id => {
                const el = document.getElementById(id)
                if(el) {
                    el.addEventListener('mouseover', this.addHoveredClass)
                    el.addEventListener('mouseout', this.removeHoveredClass)
                    el.addEventListener('click', this.selectRegion)
                }
            })
        },
        setDetailPosition(event) {
            const map = document.getElementById('map')
            if(map) {
                const regionDetails = document.getElementById('regionDetails');
                if(regionDetails) {
                    const mapRect = map.getBoundingClientRect();
                    this.left = event.clientX - mapRect.left + map.scrollLeft
                    this.top = event.clientY - mapRect.top + map.scrollTop
                }
            }
        },
        correctRegionDetailsStyle(barCount) {
            const map = document.getElementById('map')
            const paddingLeft = 5
            const paddingbottom = 25
            const regionDetailsWidth = 256
            const regionDetailsHeight = 48.02 * barCount + 10 * (barCount - 1) + 40
            let adjustmentLeft = 0, adjustmentTop = 0
            if(delete this.regionDetailsStyle.display) delete this.regionDetailsStyle.display

            if (this.left + regionDetailsWidth > map.scrollWidth) {
                adjustmentLeft = (this.left + regionDetailsWidth) - (map.scrollWidth - paddingLeft)
            }
            if (this.top + regionDetailsHeight > map.scrollHeight) {
                adjustmentTop = (this.top + regionDetailsHeight) - (map.scrollHeight - paddingbottom)
            }
            this.regionDetailsStyle.left = `${this.left - adjustmentLeft}px`
            this.regionDetailsStyle.top = `${this.top - adjustmentTop}px`
            this.regionDetailsStyle.display = 'block'
        },
        addHoveredClass(event) {
            event.target.classList.add('hovered')
        },
        removeHoveredClass(event) {
            event.target.classList.remove('hovered')
        },
        getRegionNameById(id) {
            const region = this.regionNames.find(reg => reg.id === id)
            return region ? region.name : ''
        },
        selectRegion(event) {
            if(this.selectedRegion.id && this.selectedRegion.id === event.target.id) {
                this.clearSelectedRegion()
                return
            }
            if(this.selectedRegion.id) {
                const region = document.getElementById(this.selectedRegion.id)
                const text = document.getElementById(`t_${this.selectedRegion.id}`)
                if(region) region.classList.remove('selected')
                if(text) region.classList.remove('t_selected')
            }
            this.clearSelectedRegion()
            this.selectedRegion.name = this.getRegionNameById(event.target.id)
            this.selectedRegion.id = event.target.id
            event.target.classList.add('selected')
            const text = document.getElementById(`t_${event.target.id}`)
            if(text) text.classList.add('t_selected')
            this.getRegionStat(event.target.id)
            this.setDetailPosition(event)
        },
        removeListeners() {
            this.regionIDs.forEach(id => {
                const el = document.getElementById(id)
                if(el) {
                    el.removeEventListener('mouseover', this.addHoveredClass)
                    el.removeEventListener('mouseout', this.removeHoveredClass)
                    el.removeEventListener('click', this.selectRegion)
                }
            })
        }
    }
}
</script>

